import React, { useState } from 'react';
import axios from 'axios';

const API_BASE = 'http://localhost:5000';

function TimerPanel() {
  const [minutes, setMinutes] = useState(0);
  const [seconds, setSeconds] = useState(0);
  const [addSeconds, setAddSeconds] = useState(10);
  const [timerDisplay, setTimerDisplay] = useState('00:00');
  const [isBlinking, setIsBlinking] = useState(false);

  const handleSetTimer = async () => {
    try {
      const totalSeconds = (parseInt(minutes) || 0) * 60 + (parseInt(seconds) || 0);
      await axios.post(`${API_BASE}/timer/set`, { seconds: totalSeconds });
      const mins = Math.floor(totalSeconds / 60);
      const secs = totalSeconds % 60;
      setTimerDisplay(`${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`);
      setIsBlinking(false);
    } catch (error) {
      console.error('Error setting timer:', error);
    }
  };

  const handleConfigureAddSeconds = async () => {
    try {
      await axios.post(`${API_BASE}/timer/configure`, { add_seconds: parseInt(addSeconds) || 10 });
      alert(`Konfigurisano: BTN dugme dodaje ${addSeconds} sekundi`);
    } catch (error) {
      console.error('Error configuring add seconds:', error);
    }
  };

  const handleStopTimer = async () => {
    try {
      await axios.post(`${API_BASE}/timer/stop`);
      setIsBlinking(false);
    } catch (error) {
      console.error('Error stopping timer:', error);
    }
  };

  return (
    <div className="panel">
      <h3>⏱️ Kuhinjska Štoperica</h3>

      <div className={`timer-display ${isBlinking ? 'blinking' : ''}`}>
        {timerDisplay}
      </div>

      <div className="input-group">
        <label>Minuti:</label>
        <input 
          type="number" 
          min="0" 
          max="99"
          value={minutes}
          onChange={(e) => setMinutes(e.target.value)}
          placeholder="0"
        />
      </div>

      <div className="input-group">
        <label>Sekunde:</label>
        <input 
          type="number" 
          min="0" 
          max="59"
          value={seconds}
          onChange={(e) => setSeconds(e.target.value)}
          placeholder="0"
        />
      </div>

      <button className="btn btn-primary" onClick={handleSetTimer}>
        ▶️ Postavi Timer
      </button>

      <hr style={{ margin: '15px 0', opacity: 0.3 }} />

      <div className="input-group">
        <label>BTN dodaje (N sec):</label>
        <input 
          type="number" 
          min="1" 
          max="60"
          value={addSeconds}
          onChange={(e) => setAddSeconds(e.target.value)}
          placeholder="10"
        />
      </div>

      <button className="btn btn-warning" onClick={handleConfigureAddSeconds}>
        ⚙️ Konfiguriši BTN
      </button>

      <button className="btn btn-danger" onClick={handleStopTimer} style={{ marginTop: '10px' }}>
        ⏹️ Zaustavi Treperenje
      </button>

      <div style={{ marginTop: '15px', fontSize: '0.85rem', color: 'rgba(255,255,255,0.7)' }}>
        <p>ℹ️ Pritiskom na BTN dugme dodaje se N sekundi na štopericu.</p>
        <p>Kada istekne, 4SD display treperi sa 00:00.</p>
      </div>
    </div>
  );
}

export default TimerPanel;
